// Minimal markdown parser — sufficient for our runbook rendering.
// Supports: headings, paragraphs, lists (nested), code blocks, inline code,
// bold, italic, links, blockquotes, hr, tables, images.
(function (global) {
  'use strict';

  function escapeHtml(s) {
    return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  }

  function inline(text) {
    // Escape first
    let s = escapeHtml(text);
    // Inline code
    s = s.replace(/`([^`\n]+)`/g, (_, c) => `<code>${c}</code>`);
    // Images ![alt](src) — block javascript: and data: URIs
    s = s.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, (_, alt, src) => {
      const safe = /^javascript:/i.test(src.trim()) || /^data:/i.test(src.trim()) ? '#' : src;
      return `<img alt="${alt}" src="${safe}"/>`;
    });
    // Links [text](url) — block javascript: URIs
    s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (_, text, url) => {
      const safe = /^javascript:/i.test(url.trim()) ? '#' : url;
      return `<a href="${safe}" target="_blank" rel="noopener">${text}</a>`;
    });
    // Bold **text** or __text__
    s = s.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    s = s.replace(/__([^_]+)__/g, '<strong>$1</strong>');
    // Italic *text* or _text_ (avoid mid-word)
    s = s.replace(/(^|[\s(])\*([^*\n]+)\*(?=[\s.,!?)]|$)/g, '$1<em>$2</em>');
    s = s.replace(/(^|[\s(])_([^_\n]+)_(?=[\s.,!?)]|$)/g, '$1<em>$2</em>');
    // Strikethrough ~~text~~
    s = s.replace(/~~([^~]+)~~/g, '<del>$1</del>');
    return s;
  }

  function parseTable(lines, i) {
    // Header | separator | body rows
    if (i + 1 >= lines.length) return null;
    const header = lines[i];
    const sep = lines[i + 1];
    if (!/^\s*\|?(.+\|)+.+\|?\s*$/.test(header)) return null;
    if (!/^\s*\|?[\s\-:|]+\|?\s*$/.test(sep) || !sep.includes('-')) return null;

    function cells(row) {
      return row.replace(/^\s*\|/, '').replace(/\|\s*$/, '').split('|').map(c => c.trim());
    }
    const heads = cells(header);
    let out = '<table><thead><tr>' + heads.map(h => `<th>${inline(h)}</th>`).join('') + '</tr></thead><tbody>';
    let j = i + 2;
    while (j < lines.length && /\|/.test(lines[j]) && lines[j].trim() !== '') {
      const row = cells(lines[j]);
      out += '<tr>' + row.map(c => `<td>${inline(c)}</td>`).join('') + '</tr>';
      j++;
    }
    out += '</tbody></table>';
    return { html: out, next: j };
  }

  function parseList(lines, i, indent, ordered) {
    const tag = ordered ? 'ol' : 'ul';
    let out = `<${tag}>`;
    let j = i;
    const marker = ordered ? /^(\s*)\d+\.\s+(.*)$/ : /^(\s*)[-*+]\s+(.*)$/;
    while (j < lines.length) {
      const m = lines[j].match(marker);
      if (!m) break;
      const itemIndent = m[1].length;
      if (itemIndent < indent) break;
      if (itemIndent > indent) {
        // nested — should be handled by inner call, break
        break;
      }
      let item = m[2];
      j++;
      // continuation lines and nested lists
      let inner = '';
      while (j < lines.length) {
        const nextLine = lines[j];
        const nextOrdered = nextLine.match(/^(\s*)\d+\.\s+/);
        const nextUnordered = nextLine.match(/^(\s*)[-*+]\s+/);
        const nextMarker = nextOrdered || nextUnordered;
        if (nextMarker && nextMarker[1].length > indent) {
          const sub = parseList(lines, j, nextMarker[1].length, !!nextOrdered);
          inner += sub.html;
          j = sub.next;
          continue;
        }
        // blank line ends the item
        if (nextLine.trim() === '') break;
        // Same or higher level list item ends item
        if (nextMarker && nextMarker[1].length <= indent) break;
        // Otherwise it's a continuation
        item += ' ' + nextLine.trim();
        j++;
      }
      out += `<li>${inline(item)}${inner}</li>`;
    }
    out += `</${tag}>`;
    return { html: out, next: j };
  }

  function parse(md) {
    if (!md) return '';
    const lines = md.replace(/\r\n/g, '\n').split('\n');
    let html = '';
    let i = 0;
    let paragraph = [];

    function flushPara() {
      if (paragraph.length) {
        html += '<p>' + inline(paragraph.join(' ')) + '</p>';
        paragraph = [];
      }
    }

    while (i < lines.length) {
      const line = lines[i];

      // Fenced code block
      const fence = line.match(/^```(\w*)\s*$/);
      if (fence) {
        flushPara();
        const lang = fence[1];
        i++;
        let code = '';
        while (i < lines.length && !/^```\s*$/.test(lines[i])) {
          code += lines[i] + '\n';
          i++;
        }
        i++; // skip closing
        html += `<pre><code class="lang-${lang}">${escapeHtml(code)}</code></pre>`;
        continue;
      }

      // Headings
      const h = line.match(/^(#{1,6})\s+(.+?)\s*#*\s*$/);
      if (h) {
        flushPara();
        const level = h[1].length;
        html += `<h${level}>${inline(h[2])}</h${level}>`;
        i++;
        continue;
      }

      // Horizontal rule
      if (/^\s*(?:-{3,}|_{3,}|\*{3,})\s*$/.test(line)) {
        flushPara();
        html += '<hr/>';
        i++;
        continue;
      }

      // Blockquote
      if (/^>\s?/.test(line)) {
        flushPara();
        let bq = '';
        while (i < lines.length && /^>\s?/.test(lines[i])) {
          bq += lines[i].replace(/^>\s?/, '') + '\n';
          i++;
        }
        html += '<blockquote>' + parse(bq) + '</blockquote>';
        continue;
      }

      // Table
      if (/\|/.test(line) && i + 1 < lines.length && /^[\s\-:|]+$/.test(lines[i + 1]) && lines[i + 1].includes('-')) {
        flushPara();
        const t = parseTable(lines, i);
        if (t) {
          html += t.html;
          i = t.next;
          continue;
        }
      }

      // Lists
      const ol = line.match(/^(\s*)\d+\.\s+/);
      const ul = line.match(/^(\s*)[-*+]\s+/);
      if (ol || ul) {
        flushPara();
        const indent = (ol || ul)[1].length;
        const list = parseList(lines, i, indent, !!ol);
        html += list.html;
        i = list.next;
        continue;
      }

      // Blank line
      if (line.trim() === '') {
        flushPara();
        i++;
        continue;
      }

      // Paragraph accumulation
      paragraph.push(line.trim());
      i++;
    }

    flushPara();
    return html;
  }

  global.marked = { parse };
})(typeof window !== 'undefined' ? window : this);
